/**
 * Human approval of a reconciliation card. The server RE-DERIVES and
RE-VALIDATES the whole graph (it never trusts UI-supplied locks) and runs the
consistency gate before committing in one transaction: QB present + not already
reconciled; exactly one donor (Donor XOR); gift donor == opportunity donor;
the gift is not already claimed by another evidence row; amount/date within the
fee-band tolerance unless an override reason is given; Stripe GROSS takes
precedence over the QB net when a charge is selected; nothing is archived.
Minting a gift is human-only. Idempotent: re-approving a reconciled card
returns its current state.

Source groups (a card whose stagedPaymentId belongs to a unit group)
approve as a WHOLE: the create-* outcomes mint ONE gift whose amount sums
every non-archived member, booking one counted payment_applications
ledger row per member (the representative's row carries
created_the_gift, so no slice can
be reconciled twice); link_existing_gift is rejected (409
source_group_use_reconcile) — link the whole group via group-reconcile
instead; and a group whose members carry a tied Stripe payout, or an
explicit Stripe charge selection, is rejected (409
source_group_stripe_unsupported) since per-charge GROSS can't yet be
summed across a group (ungroup to reconcile those individually).

 * @summary Approve a card — link or human-mint a gift, enforcing all invariants server-side.
 */
export const ApproveReconciliationCardParams = zod.object({
  "stagedPaymentId": zod.coerce.string()
})

export const ApproveReconciliationCardBody = zod.object({
  "outcome": zod.enum(['link_existing_gift', 'create_gift', 'create_gift_from_opportunity', 'convert_to_pledge_and_first_payment']).describe('What approving the card does.\nlink_existing_gift: tie the QB (+Stripe) evidence to an existing gift; no new gift.\ncreate_gift: human-mint a new gift from the QB evidence for the chosen donor.\ncreate_gift_from_opportunity: mint a one-time gift and link it to the chosen opportunity (opportunityId); the opp derives to cash_in when fully paid.\nconvert_to_pledge_and_first_payment: latch the opportunity as a pledge (set writtenPledge=true; cultivation stage is untouched) and mint the first-payment gift linked to it.\n'),
  "giftId": zod.string().nullish().describe('Existing gift to link (required for link_existing_gift).'),
  "opportunityId": zod.string().nullish().describe('Opportunity\/pledge to generate from or link to (required for the \*_opportunity \/ convert_\* outcomes).'),
  "organizationId": zod.string().nullish().describe('Donor XOR — set exactly one of the three donor FKs when creating a gift and the donor isn\'t derivable.'),
  "individualGiverPersonId": zod.string().nullish(),
  "householdId": zod.string().nullish(),
  "paymentIntermediaryId": zod.string().nullish().describe('Optional DAF \/ giving-platform conduit the donor gave through.'),
  "switchGiftDonor": zod.boolean().nullish().describe('For link_existing_gift ONLY: when true, re-point the existing gift\'s donor to the single donor FK supplied in this body (after explicit human confirmation in the UI). Blocked (409 gift_pledge_donor_conflict) when the gift is a payment on a pledge\/opportunity owned by a different donor — fix the pledge first.'),
  "switchStripeSource": zod.boolean().nullish().describe('For link_existing_gift ONLY: when true, re-source the existing gift from the Stripe charge selected in stripeChargeId, orphaning the charge that currently backs it (which returns to the unmatched-money queue as pending) and recording an audit entry — after explicit human confirmation in the UI. When omitted and the gift is already sourced from a DIFFERENT charge, the approve is blocked (409 consistency_gate, issue code gift_already_stripe_sourced) whose details carry the current backing charge (id, amount, payer, date) so the UI can describe the switch.'),
  "displaceLinkedPayment": zod.boolean().nullish().describe('For link_existing_gift ONLY: when true, re-target the existing gift onto THIS payment even though another (incumbent) QuickBooks staged payment is already linked to it — disconnecting the incumbent and returning it to the unmatched\/pending queue first, then linking this one, recording an audit entry — after explicit human confirmation in the UI. When omitted and the gift is already linked to a different staged payment, the approve is blocked (409 consistency_gate, issue code gift_already_qb_linked) whose details carry the incumbent payment (id, amount, payer, date) so the UI can describe the displacement. Composes with switchStripeSource so a Stripe-backed deposit resolves both conflicts in one confirmation. Only a DIRECT match incumbent is displaceable; a gift linked through a group or split is refused (409 incumbent_not_displaceable) — revert that first.'),
  "moveOwnApplication": zod.boolean().nullish().describe('For link_existing_gift ONLY: when true, re-target THIS payment onto the selected gift even though the payment itself is already applied to a DIFFERENT gift (e.g. the sync worker auto-matched it to the wrong one of two identical donations) — the commit first unwinds the payment\'s own existing cash-application (removes its ledger rows, reverses its final-amount stamp on the OLD gift, re-derives that gift\'s pledge and QuickBooks tie status, records an audit entry on the old gift), then applies it to the newly selected gift — after explicit human confirmation in the UI. When omitted and the payment is already applied elsewhere, the approve is blocked (409 consistency_gate, issue code payment_already_applied) whose details carry the currently applied gift (id, name, amount, date) so the UI can describe the move. Composes with switchStripeSource and displaceLinkedPayment so all three conflicts resolve in one confirmation. Only a DIRECT own-match is movable; a payment applied through a group, a split, or one that minted its gift is refused — revert that first.'),
  "stripeChargeId": zod.string().nullish().describe('The Stripe charge whose GROSS becomes the gift\'s final amount (Stripe precedence). Omit for QB-only money (brokerage\/check).'),
  "overrideAmountMismatchReason": zod.string().nullish().describe('Required to approve when the evidence amount and the gift amount fall outside the fee-band tolerance.'),
  "splitGroupIntoAllocations": zod.boolean().nullish().describe('For a SOURCE GROUP create_gift ONLY: when true, seed one gift allocation per grouped staged payment (sub_amount = that member\'s amount, entity from its attributed entityId) so the subcomponents become allocation rows summing to the gift total. When false\/omitted the gift is header-only. Ignored for single (non-group) cards and for the opportunity outcomes (those seed allocations from the pledge).')
}).describe('Approve a reconciliation card. The server re-derives and re-validates the entire graph and runs the consistency gate before committing; it never trusts UI-supplied locks.')

export const ApproveReconciliationCardResponse = zod.object({
  "ok": zod.literal(true),
  "outcome": zod.enum(['link_existing_gift', 'create_gift', 'create_gift_from_opportunity', 'convert_to_pledge_and_first_payment']).describe('What approving the card does.\nlink_existing_gift: tie the QB (+Stripe) evidence to an existing gift; no new gift.\ncreate_gift: human-mint a new gift from the QB evidence for the chosen donor.\ncreate_gift_from_opportunity: mint a one-time gift and link it to the chosen opportunity (opportunityId); the opp derives to cash_in when fully paid.\nconvert_to_pledge_and_first_payment: latch the opportunity as a pledge (set writtenPledge=true; cultivation stage is untouched) and mint the first-payment gift linked to it.\n'),
  "stagedPaymentId": zod.string(),
  "giftId": zod.string().describe('The existing-or-newly-created gift the evidence is now tied to.'),
  "opportunityId": zod.string().nullish(),
  "createdGift": zod.boolean().describe('True when a new gift was minted.'),
  "createdPledge": zod.boolean().describe('True when an opportunity was latched into a pledge.')
})

